const raw = $input.item.json.output ?? $input.item.json.text ?? $input.item.json.message ?? '';
const cleaned = String(raw).replace(/```json/gi, '').replace(/```/g, '').trim();
let intent;
try { intent = JSON.parse(cleaned); } catch(e) { intent = { destination_place: null, destination_is_station: false, origin_place: null, origin_is_station: false, passengers: 1, requested_arrival_time: null, is_location_shared: false, parse_error: true }; }
return [{ json: intent }];

// ====== PROCESS QUERY ======
const pre = $('Execute Workflow Trigger').first().json;
const intent = $('Parse Intent').first().json;
const gtfs = $('Load GTFS').first().json;

// stations is a DICT: { "Aluva": {id, lat, lon, zone}, "Pulinchodu": {...}, ... }
const stationsObj = gtfs.stations || {};
// Convert to array with name property for easier processing
const stations = Object.entries(stationsObj).map(([name, data]) => ({ name, ...data }));
const line = gtfs.line || [];
const schedule = gtfs.schedule || [];
const fares = gtfs.fares || {};

const passengers = intent.passengers ?? 1;

function matchStation(searchName) {
    if (!searchName) return null;
    const s1 = String(searchName).toLowerCase().replace(/[^a-z0-9]/g, '');
    for (const st of stations) {
        const s2 = String(st.name).toLowerCase().replace(/[^a-z0-9]/g, '');
        if (s1 === s2) return st;  // exact match first
    }
    for (const st of stations) {
        const s2 = String(st.name).toLowerCase().replace(/[^a-z0-9]/g, '');
        if (s1.includes(s2) || s2.includes(s1)) return st;
    }
    return null;
}

function isValidCoord(v) {
    if (v === null || v === undefined) return false;
    const s = String(v).trim();
    if (s === '' || s === 'null' || s === 'undefined' || s === 'NaN') return false;
    const n = parseFloat(s);
    return !isNaN(n) && isFinite(n) && n !== 0;
}

function extractCoordsFromText(text) {
    if (!text) return null;
    const s = String(text);
    const patterns = [
        /\[User location:\s*([\d.]+)\s*,\s*([\d.]+)\s*\]/i,
        /\[COORDS:\s*([\d.]+)\s*,\s*([\d.]+)\s*\]/i,
        /^\s*([\d]+\.\d{3,})\s*[,\s]\s*([\d]+\.\d{3,})/m,
        /([\d]+\.\d{3,})\s*[,\s]\s*([\d]+\.\d{3,})/
    ];
    for (const p of patterns) {
        const m = s.match(p);
        if (m) {
            const lat = parseFloat(m[1]);
            const lon = parseFloat(m[2]);
            if (lat >= 8 && lat <= 13 && lon >= 74 && lon <= 78) return { lat, lon };
            if (lon >= 8 && lon <= 13 && lat >= 74 && lat <= 78) return { lat: lon, lon: lat };
        }
    }
    return null;
}

// ORIGIN INPUT
let originLat = null;
let originLon = null;
let originIsLocationPin = false;

// Priority 1: Direct coordinates from trigger
if (isValidCoord(pre.latitude) && isValidCoord(pre.longitude)) {
    originLat = parseFloat(pre.latitude);
    originLon = parseFloat(pre.longitude);
    originIsLocationPin = true;
}
// Priority 2: Coordinates in userMessage text
if (originLat === null) {
    const fromMsg = extractCoordsFromText(pre.userMessage);
    if (fromMsg) { originLat = fromMsg.lat; originLon = fromMsg.lon; originIsLocationPin = true; }
}
// Priority 3: Origin is a named station
if (originLat === null && intent.origin_is_station && intent.origin_place) {
    const station = matchStation(intent.origin_place);
    if (station) { originLat = station.lat; originLon = station.lon; }
}
// Priority 4: Origin was geocoded
if (originLat === null) {
    try { const nom = $('Resolve Origin').first().json; if (isValidCoord(nom.lat)) { originLat = parseFloat(nom.lat); originLon = parseFloat(nom.lon); } } catch(e) {}
}
if (originLat === null) {
    try { const ph = $('Fallback Origin').first().json; if (ph && ph.features && ph.features.length > 0) { const c = ph.features[0].geometry.coordinates; originLat = c[1]; originLon = c[0]; } } catch(e) {}
}

if (originLat === null || originLon === null) return [{ json: { error: 'no_origin' } }];

// DESTINATION INPUT
let destLat = null;
let destLon = null;
const destName = intent.destination_place || 'Destination';

// Station match first
if (intent.destination_is_station && intent.destination_place) {
    const station = matchStation(intent.destination_place);
    if (station) { destLat = station.lat; destLon = station.lon; }
}
// Geocoded fallback
if (destLat === null) {
    try { const nom = $('Resolve Destination').first().json; if (isValidCoord(nom.lat)) { destLat = parseFloat(nom.lat); destLon = parseFloat(nom.lon); } } catch(e) {}
}
if (destLat === null) {
    try { const ph = $('Fallback Destination').first().json; if (ph && ph.features && ph.features.length > 0) { const c = ph.features[0].geometry.coordinates; destLat = c[1]; destLon = c[0]; } } catch(e) {}
}

if (destLat === null || destLon === null) return [{ json: { error: 'dest_not_found' } }];

// HELPERS
function haversine(lat1, lon1, lat2, lon2) {
    const R = 6371;
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;
    const a = Math.sin(dLat/2)**2 + Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dLon/2)**2;
    return R * 2 * Math.asin(Math.sqrt(a));
}

function findClosestStation(lat, lon) {
    let closest = null, minDist = Infinity;
    for (const s of stations) {
        const d = haversine(lat, lon, s.lat, s.lon);
        if (d < minDist) { minDist = d; closest = s; }
    }
    return closest;
}

const entryStation = findClosestStation(originLat, originLon);
const exitStation = findClosestStation(destLat, destLon);

if (!entryStation || !exitStation) return [{ json: { error: 'station_not_found' } }];
if (entryStation.name === exitStation.name) return [{ json: { error: 'same_station', entryStation: entryStation.name } }];

// TRAVEL TIMES
const distToEntry = haversine(originLat, originLon, entryStation.lat, entryStation.lon);
const toEntryWalk = Math.max(1, Math.round((distToEntry / 5) * 60));
const toEntryVehicle = Math.max(1, Math.round((distToEntry / 20) * 60));

const distFromExit = haversine(exitStation.lat, exitStation.lon, destLat, destLon);
const fromExitWalk = Math.max(1, Math.round((distFromExit / 5) * 60));
const fromExitVehicle = Math.max(1, Math.round((distFromExit / 20) * 60));

let stopCount = 0;
const entryIndex = line.indexOf(entryStation.name);
const exitIndex = line.indexOf(exitStation.name);
if (entryIndex !== -1 && exitIndex !== -1) stopCount = Math.abs(entryIndex - exitIndex);

// SCHEDULE — offset by time to reach station
const now = new Date();
const utcNow = now.getTime() + (now.getTimezoneOffset() * 60000);
const istNow = new Date(utcNow + (330 * 60000));
const arrivalAtStation = new Date(istNow.getTime() + (toEntryVehicle * 60000));
const arrH = arrivalAtStation.getHours(), arrM = arrivalAtStation.getMinutes(), arrS = arrivalAtStation.getSeconds();
const arrivalTimeStr = `${String(arrH).padStart(2,'0')}:${String(arrM).padStart(2,'0')}:${String(arrS).padStart(2,'0')}`;

let entrySchedules = [];
if (Array.isArray(schedule)) {
    entrySchedules = schedule.filter(s => s.stop_id === entryStation.id || s.stop_id === entryStation.name);
} else if (schedule[entryStation.id] || schedule[entryStation.name]) {
    const arr = schedule[entryStation.id] || schedule[entryStation.name];
    entrySchedules = arr.map(t => ({ stop_id: entryStation.id, departure_time: t.time || t.departure_time || t }));
}
entrySchedules = entrySchedules.filter(s => (s.departure_time || '') >= arrivalTimeStr);
entrySchedules.sort((a,b) => (a.departure_time||'').localeCompare(b.departure_time||''));

const nextTrain = entrySchedules.length > 0 ? entrySchedules[0] : null;
let metroMinutes = 0, scheduleUsed = false, nextDepartureTime = 'N/A';

const parseTime = t => { const p = typeof t==='string'?t.split(':').map(Number):[0,0]; return p[0]*60+p[1]+(p[2]||0)/60; };

if (nextTrain) {
    nextDepartureTime = (nextTrain.departure_time || '').slice(0,5);
    let exitSch = null;
    if (nextTrain.trip_id && Array.isArray(schedule)) {
        exitSch = schedule.find(s => s.trip_id === nextTrain.trip_id && (s.stop_id === exitStation.id || s.stop_id === exitStation.name));
    }
    if (exitSch) {
        metroMinutes = Math.max(1, Math.round(Math.abs(parseTime(exitSch.departure_time) - parseTime(nextTrain.departure_time))));
        scheduleUsed = true;
    } else {
        metroMinutes = Math.max(1, Math.round(stopCount * 2.5));
    }
} else {
    metroMinutes = Math.max(1, Math.round(stopCount * 2.5));
}

const totalWalk = toEntryWalk + metroMinutes + fromExitWalk;
const totalVehicle = toEntryVehicle + metroMinutes + fromExitVehicle;

// FARE
let fare = 0;
const key = `${entryStation.zone}_${exitStation.zone}`;
if (fares[key]) fare = fares[key] * passengers;
else if (fares[stopCount]) fare = fares[stopCount] * passengers;
else {
    const dist = haversine(entryStation.lat, entryStation.lon, exitStation.lat, exitStation.lon);
    fare = (dist<=2?10:dist<=5?20:dist<=10?30:dist<=15?40:dist<=20?50:60) * passengers;
}

return [{
    json: {
        entryStation: entryStation.name,
        exitStation: exitStation.name,
        entryLat: entryStation.lat,
        entryLon: entryStation.lon,
        exitLat: exitStation.lat,
        exitLon: exitStation.lon,
        originLat, originLon,
        originIsLocationPin,
        originPlace: intent.origin_place || null,
        destLat, destLon,
        destName,
        fare, passengers,
        toEntryWalk, toEntryVehicle,
        metroMinutes,
        fromExitWalk, fromExitVehicle,
        totalWalk, totalVehicle,
        scheduleUsed, nextDepartureTime,
        nextTrains: [nextDepartureTime],
        stopCount,
        error: null
    }
}];

const q = $input.item ? $input.item.json : $json;

if (q.error === 'no_origin') {
  return [{ json: { replyMessage: '📍 Where are you starting from? Share your live location or type a place name \n(e.g. \'from Kakkanad\' or \'from Aluva station\')' } }];
}
if (q.error === 'dest_not_found') {
  return [{ json: { replyMessage: '❌ Could not find that destination. Please try again with a clearer name.' } }];
}
if (q.error === 'same_station') {
  return [{ json: { replyMessage: `📍 Your origin and destination are both closest to ${q.entryStation} station. You might not need the metro for this trip!` } }];
}
if (q.error) {
  return [{ json: { replyMessage: '⚠️ Something went wrong planning your route. Please try again.' } }];
}

// Build Google Maps URL with names, except origin uses coords if from a location pin
const originPart = q.originIsLocationPin
  ? `${q.originLat},${q.originLon}`
  : encodeURIComponent(q.originPlace || `${q.originLat},${q.originLon}`);
const entryPart = encodeURIComponent(`${q.entryStation} Metro Station, Kochi`);
const exitPart = encodeURIComponent(`${q.exitStation} Metro Station, Kochi`);
const destPart = encodeURIComponent(`${q.destName}, Kochi`);

const mapsUrl = `https://www.google.com/maps/dir/${originPart}/${entryPart}/${exitPart}/${destPart}`;

let reply = `📍 ${q.entryStation} → ${q.exitStation}`;
reply += `\n💰 ₹${q.fare}`;
if (q.passengers > 1) reply += ` (${q.passengers} passengers)`;
reply += `\n\n🗺 Getting there:`;
reply += `\n~${q.toEntryWalk} min walk or ~${q.toEntryVehicle} min by vehicle to ${q.entryStation}`;
reply += `\n\n🚇 Metro ride: ~${q.metroMinutes} min (${q.stopCount} stops)`;
reply += `\nNext train: ${q.nextDepartureTime}`;
reply += `\n\n🏁 From ${q.exitStation} to ${q.destName}:`;
reply += `\n~${q.fromExitWalk} min walk or ~${q.fromExitVehicle} min by vehicle`;
reply += `\n\n⏱ Total estimate:`;
reply += `\n~${q.totalWalk} min (walking) | ~${q.totalVehicle} min (vehicle)`;
reply += `\n\n🗺 View full route on Maps:`;
reply += `\n${mapsUrl}`;

if (q.scheduleUsed === false) {
  reply += `\n\n⚠️ Train time is estimated (live schedule unavailable)`;
}

return [{ json: { replyMessage: reply } }];
